  },
  {
   "url": "https://www.dmtf.org/sites/default/files/standards/documents/DSP2056_1.1.0.pdf",
   "stance": "contradicts",
   "quote": "Redfish for Power Distribution Equipment"
  },
  {
   "url": "https://www.potaroo.net/ietf/ids/draft-ahc-green-smartpdu-yang-00.txt",
   "stance": "contradicts",
   "quote": "Current SmartPDU solutions are largely proprietary, exposing heterogeneous APIs and data formats that complicate integration and automation. The proposed YANG model provides a vendor-neutral framework for configuration, monitoring, and control of intelligent power distribution systems."
  },
  {
   "url": "https://download.schneider-electric.com/files?p_Doc_Ref=TME45037&p_File_name=NetShelter+Rack+PDU+Modbus+Register+Map_TME45037.pdf",
   "stance": "contradicts",
