   "stance": "contradicts",
   "quote": "NRGence eco PDU supports any 3rd party V3 SNMP Manager Software"
  },
  {
   "url": "https://www.tuev-nord.de/en/services/auditing-and-certification/en-50600/",
   "stance": "silent",
   "quote": "The European standard EN 50600 provides comprehensive guidelines for the planning, construction, and operation of data centers"
  }
 ]
}

